mapper.update:
UPDATE reservations
SET status = #{toStatus},
    verified_at = CASE WHEN #{toStatus} = 'verified' THEN #{verifiedAt} ELSE verified_at END,
    verified_by = CASE WHEN #{toStatus} = 'verified' THEN #{verifiedBy} ELSE verified_by END
WHERE id = #{id}
  AND status = #{fromStatus}

mapper.select:
SELECT COUNT(*)
FROM reservations
WHERE court_id = #{courtId}
  AND reserve_date = #{date}
  AND start_time = #{startTime}
  AND status NOT IN ('cancelled')

SELECT r.*, c.name AS courtName, u.avatar AS userAvatar, u.gender AS userGender,
       u.nickname AS userNickname, u.phone AS userPhone
FROM reservations r
         JOIN courts c ON r.court_id = c.id
         JOIN users u ON r.user_id = u.id


        AND r.status = #{status}


        AND r.reserve_date = #{date}


        AND r.court_id = #{courtId}


ORDER BY r.reserve_date DESC, r.start_time DESC, r.id DESC
